#include <stdio.h>
#include <stdlib.h>

int main()
{
    int n, m, ans, ans2, max, dima, total;
    ans2 = 0;
    ans = 0;
    scanf("%d", &n);
    total = n+1;
    while(n--){
        scanf("%d", &m);
        ans = ans+m;
    }
    max = ans + 5;
    dima = total + 1;
    while(1){
        if(dima>ans && dima<=max){
            ans2++;
        }
        dima +=total;
        if(dima>max) break;
    }
    ans2 = 5 - ans2;
    printf("%d\n", ans2);
    return 0;
}

