fn main() {
    let friend_count = get_input_usize();
    let finger_count: usize = get_input().split_ascii_whitespace().map(|v| v.parse::<usize>().unwrap()).sum();

    let total_people = friend_count + 1;
    let position = finger_count % total_people;

    let res = vec![1,2,3,4,5].iter().fold(0, |res, next| {
        if (next + position) % total_people == 1 {
            res
        } else {
            res + 1
        }
    });

    println!("{}", res);

}


fn get_input() -> String {
    let mut buffer = String::new();
    std::io::stdin().read_line(&mut buffer).expect("Failed");
    buffer.trim().to_owned()
}

fn get_input_usize() -> usize {
    get_input().parse().unwrap()
}
